-- Create trigger function to insert a profile row after a user is inserted
CREATE OR REPLACE FUNCTION create_profile_on_user_insert()
RETURNS trigger
LANGUAGE plpgsql
AS $$
DECLARE
    site_name text;
    normalized_url text;
BEGIN
    -- Derive WebsiteUrl => take part after http(s):// (and optional www.) and before ".com"
    IF NEW.websiteurl IS NOT NULL AND NEW.websiteurl <> '' THEN
        normalized_url := lower(NEW.websiteurl);

        -- strip protocol and optional leading www.
        normalized_url := regexp_replace(normalized_url, '^[a-z]+://', '');
        normalized_url := regexp_replace(normalized_url, '^www\.', '');

        -- extract the portion before ".com"
        site_name := substring(normalized_url FROM '^([^/]+?)(?=\.com(?:/|$))');

        -- Fallbacks if the pattern didn't match
        IF site_name IS NULL OR site_name = '' THEN
            -- take host, drop path
            site_name := split_part(regexp_replace(lower(NEW.websiteurl), '^[a-z]+://', ''), '/', 1);
            -- remove trailing .com if present
            site_name := regexp_replace(site_name, '\.com$', '');
        END IF;
    END IF;

    INSERT INTO profiles (id, creationdate, websiteurl)
    VALUES (NEW.id::text, NEW.creationdate::text, site_name);

    RETURN NEW;
END;
$$;

-- Create the trigger on users
DROP TRIGGER IF EXISTS trg_create_profile_on_user_insert ON users;
CREATE TRIGGER trg_create_profile_on_user_insert
AFTER INSERT ON users
FOR EACH ROW
EXECUTE FUNCTION create_profile_on_user_insert();

