CREATE OR REPLACE FUNCTION ffill_state(state anyelement, new_value anyelement)
RETURNS anyelement AS $$
BEGIN
   IF new_value IS NOT NULL THEN
      RETURN new_value;
   ELSE
      RETURN state;
   END IF;
END;
$$ LANGUAGE plpgsql;

CREATE AGGREGATE ffill(anyelement) (
   SFUNC = ffill_state,
   STYPE = anyelement
);

-- Query for the superhero table with forward fill
SELECT id, publisher_id, height_cm, weight_kg,
       ffill(height_cm) OVER (PARTITION BY publisher_id ORDER BY id) AS height_cm_filled,
       ffill(weight_kg) OVER (PARTITION BY publisher_id ORDER BY id) AS weight_kg_filled
FROM superhero;

